import React from 'react';
import './Multimedia.css';
import { photos } from '../Photography.js';

const headline = 'Rats Orchestrate Takeover of New York City';

class Multimedia extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      max: photos.length - 1,
      index: 0,
    };
  }

  increase = (direction) => {
    let newIndex = this.state.index + direction;

    if (newIndex == -1)
      { newIndex = this.state.max; }
    else if (newIndex == this.state.max + 1)
      { newIndex = 0; }

    this.setState({
     index: newIndex
    });
  }

  expand = (test) => {
    console.log(test)
  }



  render() {
    return (
      <div className='Multimedia'>
        <div className='photosection' id='reporting' onClick={() => {this.expand(this); console.log(this.target.id)}}>
          <div className='linkbox'>Reporting</div>
        </div>
        <div className='photosection'>
          <div className='linkbox'>Photography and Multimedia</div>
        </div>   
        <div className='photosection'>
          <div className='linkbox'>Data and Coding</div>
        </div>
      </div>
    );
  }
}

export default Multimedia;
